UPDATE notification
SET is_read = TRUE
WHERE notification_id = #{notificationId}
  AND user_id = #{userId}

UPDATE notification
SET is_read = TRUE
WHERE user_id = #{userId}

UPDATE notification
SET is_read = TRUE
WHERE user_id = #{userId}
  AND is_read = FALSE
  AND notification_id IN (
    SELECT notification_id
    FROM (
      SELECT notification_id
      FROM notification
      WHERE user_id = #{userId}
        AND is_read = FALSE
      ORDER BY created_at DESC
      LIMIT #{limit}
    ) t
  )

